     6→namespace Envoy {
     7→namespace Extensions {
     8→namespace HttpFilters {
     9→namespace Common {
    10→
    11→/**
    12→ * Common base class for HTTP filter factory registrations. Removes a substantial amount of
    13→ * boilerplate.
    14→ */
    15→template <class ConfigProto, class RouteConfigProto = ConfigProto>
    16→class CommonFactoryBase : public virtual Server::Configuration::HttpFilterConfigFactoryBase {
    17→public:
    18→  ProtobufTypes::MessagePtr createEmptyConfigProto() override {
    19→    return std::make_unique<ConfigProto>();
    20→  }
    21→
    22→  ProtobufTypes::MessagePtr createEmptyRouteConfigProto() override {
    23→    return std::make_unique<RouteConfigProto>();
    24→  }
    25→
    26→  Router::RouteSpecificFilterConfigConstSharedPtr
    27→  createRouteSpecificFilterConfig(const Protobuf::Message& proto_config,
    28→                                  Server::Configuration::ServerFactoryContext& context,
    29→                                  ProtobufMessage::ValidationVisitor& validator) override {
    30→    return createRouteSpecificFilterConfigTyped(
    31→        MessageUtil::downcastAndValidate<const RouteConfigProto&>(proto_config, validator), context,
    32→        validator);
    33→  }
    34→
    35→  std::string name() const override { return name_; }
    36→
    37→  bool isTerminalFilterByProto(const Protobuf::Message& proto_config,
    38→                               Server::Configuration::ServerFactoryContext& context) override {
    39→    return isTerminalFilterByProtoTyped(MessageUtil::downcastAndValidate<const ConfigProto&>(
    40→                                            proto_config, context.messageValidationVisitor()),
    41→                                        context);
    42→  }
    43→
    44→  virtual bool isTerminalFilterByProtoTyped(const ConfigProto&,
    45→                                            Server::Configuration::ServerFactoryContext&) {
    46→    return false;
    47→  }
    48→
    49→protected:
    50→  CommonFactoryBase(const std::string& name) : name_(name) {}
    51→
    52→  virtual Router::RouteSpecificFilterConfigConstSharedPtr
    53→  createRouteSpecificFilterConfigTyped(const RouteConfigProto&,
    54→                                       Server::Configuration::ServerFactoryContext&,
    55→                                       ProtobufMessage::ValidationVisitor&) {
    56→    return nullptr;
    57→  }
    58→
    59→  const std::string name_;
    60→};
    61→
    62→template <class ConfigProto, class RouteConfigProto = ConfigProto>
    63→class FactoryBase : public CommonFactoryBase<ConfigProto, RouteConfigProto>,
    64→                    public Server::Configuration::NamedHttpFilterConfigFactory {
    65→public:
    66→  FactoryBase(const std::string& name) : CommonFactoryBase<ConfigProto, RouteConfigProto>(name) {}
    67→
    68→  absl::StatusOr<Envoy::Http::FilterFactoryCb>
    69→  createFilterFactoryFromProto(const Protobuf::Message& proto_config,
    70→                               const std::string& stats_prefix,
    71→                               Server::Configuration::FactoryContext& context) override {
    72→    return createFilterFactoryFromProtoTyped(MessageUtil::downcastAndValidate<const ConfigProto&>(
    73→                                                 proto_config, context.messageValidationVisitor()),
    74→                                             stats_prefix, context);
    75→  }
    76→  virtual Envoy::Http::FilterFactoryCb
    77→  createFilterFactoryFromProtoTyped(const ConfigProto& proto_config,
    78→                                    const std::string& stats_prefix,
    79→                                    Server::Configuration::FactoryContext& context) PURE;
    80→
    81→  Envoy::Http::FilterFactoryCb createFilterFactoryFromProtoWithServerContext(
    82→      const Protobuf::Message& proto_config, const std::string& stats_prefix,
    83→      Server::Configuration::ServerFactoryContext& server_context) override {
    84→    return createFilterFactoryFromProtoWithServerContextTyped(
    85→        MessageUtil::downcastAndValidate<const ConfigProto&>(
    86→            proto_config, server_context.messageValidationVisitor()),
    87→        stats_prefix, server_context);
    88→  }
    89→
    90→  virtual Envoy::Http::FilterFactoryCb
    91→  createFilterFactoryFromProtoWithServerContextTyped(const ConfigProto&, const std::string&,
    92→                                                     Server::Configuration::ServerFactoryContext&) {
    93→    ExceptionUtil::throwEnvoyException(
    94→        "Creating filter factory from server factory context is not supported");
    95→    return nullptr;
    96→  }
    97→};
