   144→                                             stats_prefix, DualInfo(context),
   145→                                             context.serverFactoryContext());
   146→  }
   147→
   148→  absl::StatusOr<Envoy::Http::FilterFactoryCb>
   149→  createFilterFactoryFromProto(const Protobuf::Message& proto_config,
   150→                               const std::string& stats_prefix,
   151→                               Server::Configuration::UpstreamFactoryContext& context) override {
   152→    return createFilterFactoryFromProtoTyped(
   153→        MessageUtil::downcastAndValidate<const ConfigProto&>(
   154→            proto_config, context.serverFactoryContext().messageValidationVisitor()),
   155→        stats_prefix, DualInfo(context), context.serverFactoryContext());
   156→  }
   157→
   158→  virtual absl::StatusOr<Envoy::Http::FilterFactoryCb>
   159→  createFilterFactoryFromProtoTyped(const ConfigProto& proto_config,
   160→                                    const std::string& stats_prefix, DualInfo info,
   161→                                    Server::Configuration::ServerFactoryContext& context) PURE;
   162→
   163→  // This method is for dual filter to create filter from server context when it is configured
